mapper.sql:
FROM knowledge_entry e

WHERE e.status = 1

    AND e.entry_type = #{request.entryType}


    AND f.original_file_name LIKE CONCAT('%', #{request.fileName}, '%')


    AND e.entry_code LIKE CONCAT('%', #{request.entryCode}, '%')


    AND e.title LIKE CONCAT('%', #{request.title}, '%')


    AND e.profession_code = #{request.professionCode}


    AND e.info_status = #{request.infoStatus}


    AND e.release_date  >=  #{request.startDate}


    AND e.release_date  <=  #{request.endDate}

mapper.select:
SELECT COUNT(1)
FROM knowledge_entry
WHERE entry_type = #{request.entryType}
  AND entry_code = #{request.entryCode}
  AND version = #{request.version}
  AND status = 1
  AND delete_marker = 0

    AND id != #{excludedEntryId}



  AND e.entry_type = #{request.entryType}


  AND f.original_file_name LIKE CONCAT('%', #{request.fileName}, '%')


  AND f.uploaded_at  >=  #{request.uploadStartTime}


  AND f.uploaded_at  <=  #{request.uploadEndTime}

ORDER BY f.uploaded_at DESC, f.id DESC
LIMIT #{limit}

mapper.sql:
FROM knowledge_entry e INNER JOIN knowledge_file f ON f.id = ( SELECT current_file.id FROM knowledge_file current_file WHERE current_file.entry_id = e.id AND current_file.is_current = 1 AND current_file.status = 1 AND current_file.upload_status = 'success' ORDER BY current_file.uploaded_at DESC, current_file.id DESC LIMIT 1 ) WHERE e.status = 1 AND e.info_status = 1
AND e.entry_type = #{request.entryType}
AND ( e.title LIKE CONCAT('%', #{request.queryText}, '%') OR e.keywords LIKE CONCAT('%', #{request.queryText}, '%') OR e.entry_code LIKE CONCAT('%', #{request.queryText}, '%') OR e.project_name LIKE CONCAT('%', #{request.queryText}, '%') OR e.system_source LIKE CONCAT('%', #{request.queryText}, '%') OR e.profession_code LIKE CONCAT('%', #{request.queryText}, '%') OR e.author_name LIKE CONCAT('%', #{request.queryText}, '%') OR f.original_file_name LIKE CONCAT('%', #{request.queryText}, '%') )
